var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"CATHY_CIVIL_NULL_NULL","text":{"KOREA":"......어떻게 생각해요?","JPN":"……どう思います？","ENG":"... What do you think?","TWN":"…妳怎麼看？"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CATHY_CIVIL_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"ZENA_CIVIL_NULL_NULL","text":{"KOREA":"음, 그냥 우연의 일치 아닐까?","JPN":"さあ、ただの偶然の一致じゃないかな？","ENG":"Mm, this just has to be a coincidence.","TWN":"嗯，應該只是巧合吧?"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ZENA_CIVIL_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"CATHY_CIVIL_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L6_1","type":"dialog","speaker":"CATHY_CIVIL_NULL_NULL","text":{"KOREA":"얼굴도, 이름도, 하는 짓도 아이리와 똑같아요. 이게 과연 우연일까요?","JPN":"顔も、名前も、やっていることもアイリにそっくり。果たしてこれが偶然なのかしら？","ENG":"Her face, name, and even behavior are identical to our Irie's. Are you sure this is just a coincidence?","TWN":"但長相、名字、行為都和艾莉一樣。這真的是巧合嗎?"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ZENA_CIVIL_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"CATHY_CIVIL_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L8_1","type":"dialog","speaker":"IRIE_CIVIL_NULL_NULL","text":{"KOREA":"뭐어? 아이리는 얘보다 훨씬 귀여운데~?","JPN":"ええ？　アイリ様はこの子よりずっと可愛いのに～？","ENG":"What? Irie's much cuter than this one.","TWN":"哪有？艾莉比她可愛多了。"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"IRIE_CIVIL_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"IRIE_CIVIL_NULL_NULL","text":{"KOREA":"안 그래, 제나?","JPN":"ジーナ、そう思わない？","ENG":"Don't you agree, Zena?","TWN":"對吧？珍娜？"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"IRIE_CIVIL_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"ZENA_CIVIL_NULL_NULL","text":{"KOREA":"둘 다 사고뭉치라는 점은 같아 보이는데......","JPN":"どっちもトラブルメーカーなところは、同じだと思うが……","ENG":"Both look like troublemakers.","TWN":"是啊，兩邊都是麻煩製造者，從這一點來看的話..."},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ZENA_CIVIL_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"IRIE_CIVIL_NULL_NULL","text":{"KOREA":"히잉~","JPN":"ふえ～ん。","ENG":"Hnnnggg...","TWN":"哼..."},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"IRIE_CIVIL_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"ZENA_CIVIL_NULL_NULL","text":{"KOREA":"하지만 나도 이걸 뭐라고 설명해야 할지 모르겠어.","JPN":"私もこれをどう説明すればいいかわからない。","ENG":"I don't know how to explain this, either.","TWN":"但我也不知道該怎麼解釋。"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ZENA_CIVIL_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"CATHY_CIVIL_NULL_NULL","text":{"KOREA":"아이리, 혹시 예전에 이런 영상 찍은 적 있어요?","JPN":"アイリ、前にこういう映像を撮った覚えはありませんか？","ENG":"Irie, have you ever filmed anything like this before?","TWN":"艾莉，妳該不會以前有拍過這種影片吧?"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CATHY_CIVIL_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"IRIE_CIVIL_NULL_NULL","text":{"KOREA":"후음~ 하나도 모르겠는걸~","JPN":"う～ん、全然覚えてないなぁ～。","ENG":"Mm, I don't know.","TWN":"嗯？我完全沒印象耶！"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"IRIE_CIVIL_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"IRIE_CIVIL_NULL_NULL","text":{"KOREA":"여기 나온 사람들도 다들 처음 보는 사람들이구.","JPN":"ここに出てくる人たちも初めて見る顔だし。","ENG":"I've never seen any of these people before, either.","TWN":"這裡面出現的人，我也是今天第一次見到。"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"IRIE_CIVIL_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"IRIE_CIVIL_NULL_NULL","text":{"KOREA":"앗! 혹시 아이리 님, 기억상실증에 걸린 거야? 사실은 비련의 여주인공 아니었을까?","JPN":"あっ！　ひょっとしてアイリ様、記憶喪失なのかな？\\n本当は悲恋のヒロインだったりして！","ENG":"Ah! What if Irie's suffering from amnesia? She might be a tragic heroine.","TWN":"啊！該不會我得了失憶症？就像那些悲劇裡的女主角？"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"IRIE_CIVIL_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"CATHY_CIVIL_NULL_NULL","text":{"KOREA":"그건 아니라고 보장할 수 있겠네요.","JPN":"それは違うと断言できますね。","ENG":"I guarantee that's not the case.","TWN":"我保證不是這種這樣。"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CATHY_CIVIL_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"ZENA_CIVIL_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L20_1","type":"dialog","speaker":"CATHY_CIVIL_NULL_NULL","text":{"KOREA":"이 영상 속에 나오는 장소, 아무리 봐도 우리가 사는 곳과 동떨어진 느낌이거든요.","JPN":"この映像に出てくる場所、どう見ても私たちが住んでいる所とはかけ離れています。","ENG":"The place in this video looks nothing like the world we live in.","TWN":"這段影片中出現的場景，不管怎麼看都和我們生活的地方有些遙遠。"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CATHY_CIVIL_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ZENA_CIVIL_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L21_1","type":"dialog","speaker":"CATHY_CIVIL_NULL_NULL","text":{"KOREA":"이면세계에서 무슨 일이 벌어지건 이상할 게 없다는 말도 있지만......","JPN":"裏世界ではどんなことが起きてもおかしくないという話もありますが……","ENG":"It's said that anything can happen in the Counterside,","TWN":"雖然在異界發生什麼事都不奇怪，但這..."},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CATHY_CIVIL_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ZENA_CIVIL_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L22_1","type":"dialog","speaker":"CATHY_CIVIL_NULL_NULL","text":{"KOREA":"그래도 이건 그냥 넘어갈 사안이 아니에요.","JPN":"このまま見過ごせるものではありません。","ENG":"but I don't think we can overlook this.","TWN":"但這不是可以輕易忽略的事情。"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CATHY_CIVIL_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"ZENA_CIVIL_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L23_1","type":"dialog","speaker":"CATHY_CIVIL_NULL_NULL","text":{"KOREA":"어쩌면, 관리국에 데이터를 가져가면 뭔가 실마리를 찾아낼 수 있을지도 몰라요.","JPN":"もしかすると、管理局にデータを持っていけば何か手がかりを掴めるかも。","ENG":"Maybe we should take this data to the Administration and look for clues.","TWN":"我們把這些資料帶到管理局去的話，能找到一些線索也說不定。"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CATHY_CIVIL_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ZENA_CIVIL_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L24_1","type":"dialog","speaker":"ZENA_CIVIL_NULL_NULL","text":{"KOREA":"관리국에 가져다 준다고?","JPN":"管理局に持っていくって？","ENG":"You want to take it to the Administration?","TWN":"妳是說把這些資料帶到管理局去？"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CATHY_CIVIL_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ZENA_CIVIL_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L25_1","type":"dialog","speaker":"ZENA_CIVIL_NULL_NULL","text":{"KOREA":"그랬다간...... 우리가 로스트 쉽을 털었다고 자백하는 꼴이잖아. 정상참작은 될까?","JPN":"そんなことしたら……私たちがロストシップをあさったって白状するのと同じだろ。\\n情状酌量はされるかな？","ENG":"Then, they'll know that we took it from a Lost Ship. Would they let us off the hook, under the circumstances?","TWN":"這樣做的話...我們不是等於去自首“我們打劫了失落艦船”這件事嗎？我們會被酌情處理嗎...."},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CATHY_CIVIL_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ZENA_CIVIL_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L26_1","type":"dialog","speaker":"CATHY_CIVIL_NULL_NULL","text":{"KOREA":"선택의 여지는 없어요.","JPN":"選択の余地はありません。","ENG":"Even if they don't, we got no choice.","TWN":"但我們好像也沒有選擇了。"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CATHY_CIVIL_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"ZENA_CIVIL_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L27_1","type":"dialog","speaker":"CATHY_CIVIL_NULL_NULL","text":{"KOREA":"좀 전의 그 괴상하게 생긴 괴물들이 쉽게 우릴 포기할 것 같지도 않았거든요.","JPN":"さっきの奇妙な怪物たちが簡単に私たちを諦めるとは思えませんし。","ENG":"I don't think those strange-looking monsters we met would let us go easily, either.","TWN":"剛才那些奇奇怪怪的怪物們不會輕易放棄我們的吧？"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CATHY_CIVIL_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ZENA_CIVIL_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L28_1","type":"dialog","speaker":"CATHY_CIVIL_NULL_NULL","text":{"KOREA":"만약 저 녀석들이 계속해서 우릴 추적해 온다면, 징계를 감수하고서라도 관리국에 알리는 편이 안전할 거에요.","JPN":"あいつらに追われ続けるくらいなら、\\n懲戒を覚悟してでも管理局に知らせたほうが安全なはずです。","ENG":"If they continue to follow us, we have to turn ourselves in to the Administration. I'd rather be punished than dead.","TWN":"如果那些怪獸繼續追著我們，即使接受處分，我們也會把這件事告訴管理局，因為這樣才能保證安全。"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CATHY_CIVIL_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ZENA_CIVIL_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L29_1","type":"dialog","speaker":"ZENA_CIVIL_NULL_NULL","text":{"KOREA":"윽, 일단 길거리로 내쫓기는 건 확정이겠네.","JPN":"ううっ、道端に捨てられるのは確定だな。","ENG":"Ugh, so it's guaranteed that we'll be out of job.","TWN":"唔，那我們肯定會流落街頭的。"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CATHY_CIVIL_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ZENA_CIVIL_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L30_1","type":"dialog","speaker":"CATHY_CIVIL_NULL_NULL","text":{"KOREA":"너무 걱정하지 말아요. 꼭 라이선스를 박탈당한다고 정해진 건 아니잖아요?","JPN":"あまり心配しないでください。ライセンスを剥奪されると決まったわけでもないでしょう？","ENG":"Don't worry. We don't know if we'll lose our license or not.","TWN":"別那麼擔心。我們也不是一定會被吊銷許可證。"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CATHY_CIVIL_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"ZENA_CIVIL_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L31_1","type":"dialog","speaker":"CATHY_CIVIL_NULL_NULL","text":{"KOREA":"다이브 중에 돌발사태가 벌어지는 건 흔한 일이니까 적당한 핑계만 준비하면 잘 넘어갈 수도 있고 말이죠.","JPN":"ダイブ中に起こる突発事故は珍しくないですし、\\n適当に言い訳すれば上手く逃れられるかも知れませんよ。","ENG":"Unexpected incidents are not uncommon during Dives. Maybe we can find some good excuse and get away without punishment.","TWN":"躍入中發生突發事件是常有的事情，因此我們只要準備適當的藉口，就可以順利蒙混過去的。"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CATHY_CIVIL_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ZENA_CIVIL_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L33_1","type":"dialog","speaker":"IRIE_CIVIL_NULL_NULL","text":{"KOREA":"아이리 님은 찬성~♪ 장난도 안 받아 주는 심심한 애들이랑은 놀기 어려워♪","JPN":"アイリ様は賛成～♪　イタズラが通じない退屈な子たちとは遊びたくないわ♪","ENG":"Irie's in! ♪ Irie doesn't like to play with killjoys. ♪","TWN":"艾莉贊成這個提議~♪和那些不給惡作劇的無聊小朋友玩，實在是很難的一件事♪"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"IRIE_CIVIL_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"ZENA_CIVIL_NULL_NULL","text":{"KOREA":"어쩔 수 없네......","JPN":"仕方ないな……","ENG":"Then, we really have no choice.","TWN":"受不了，真拿妳沒辦法。"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ZENA_CIVIL_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"ZENA_CIVIL_NULL_NULL","text":{"KOREA":"알겠어. 그렇게 하자.","JPN":"わかった。そうしよう。","ENG":"Okay, let's do that.","TWN":"我知道了，就這麼辦吧！"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ZENA_CIVIL_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"CATHY_CIVIL_NULL_NULL","text":{"KOREA":"좋아요. 그리고 여기 영상 자료가 하나 더 있는 것 같아요.","JPN":"決まりましたね。あと、ここに映像資料がもう一つあるようです。","ENG":"Okay. And I've found one more video.","TWN":"好啊，而且這裡好像還有一段錄影資料。"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CATHY_CIVIL_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"CATHY_CIVIL_NULL_NULL","text":{"KOREA":"어머, 이건...... 보호 알고리즘?","JPN":"あら、これは……保護アルゴリズム？","ENG":"Oh, this is... a protection algorithm?","TWN":"欸，這是……保護演算法?"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CATHY_CIVIL_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"ZENA_CIVIL_NULL_NULL","text":{"KOREA":"응? 뭐야, 이 복잡한 건?","JPN":"うん？　なんだ、この複雑なやつは？","ENG":"Mm? What's this complicated thing?","TWN":"嗯？這什麼？這麼複雜的啊？"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CATHY_CIVIL_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"ZENA_CIVIL_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L41_1","type":"dialog","speaker":"CATHY_CIVIL_NULL_NULL","text":{"KOREA":"암호화가 되어 있는 것 같은데...... 쉽게 해독하긴 어렵겠네요.","JPN":"暗号化されているみたいですが……解読は難しそうですね。","ENG":"It's encrypted. It'll be difficult to decrypt it.","TWN":"好像被加密了…不太容易破解。"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CATHY_CIVIL_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ZENA_CIVIL_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L42_1","type":"dialog","speaker":"CATHY_CIVIL_NULL_NULL","text":{"KOREA":"일단은 백업만 해 두기로 하죠.","JPN":"ひとまずバックアップだけしておきましょう。","ENG":"Let's create a backup for now.","TWN":"那我們就做個備份吧。"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CATHY_CIVIL_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ZENA_CIVIL_NULL_NULL","face":"UNIT_SURPRISE"}}}}]`);export{e as default};